def range_summary(nums):
    if not nums:
        return ''

    nums.sort()
    result = []
    start = end = nums[0]

    for num in nums[1:]:
        if num == end + 1:
            end = num
        else:
            if start == end:
                result.append(str(start))
            else:
                result.append(f'{start}-{end}')
            start = end = num

    result.append(str(start) if start == end else f'{start}-{end}')
    return ','.join(result)

# Edge case: consecutive numbers with duplicates
print(range_summary([1, 2, 2, 3, 5]))  # Output should be '1-3,5'
